input.command:
npx ts-node -e "
const { execSync } = require('child_process');
try {
  const result = execSync('nexus wpe usage', { encoding: 'utf8', timeout: 30000 });
  console.log(result);
} catch(e) {
  console.log('CLI error:', e.message);
  console.log(e.stdout || '');
}
" 2>&1 | head -60

